import{_ as n,C as r,o as l,c as s,a0 as e,E as i}from"./chunks/framework.CrGeEOPE.js";const m=JSON.parse('{"title":"Performance Benchmarks","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://qbuem.com/qbuem-json/guide/benchmarks.html"}]]},"headers":[],"relativePath":"guide/benchmarks.md","filePath":"guide/benchmarks.md"}'),o={name:"guide/benchmarks.md"};function d(c,t,g,h,u,p){const a=r("BenchmarkCi");return l(),s("div",null,[t[0]||(t[0]=e('<h1 id="performance-benchmarks" tabindex="-1">Performance Benchmarks <a class="header-anchor" href="#performance-benchmarks" aria-label="Permalink to &quot;Performance Benchmarks&quot;">​</a></h1><p>qbuem-json is engineered to be the benchmark leader in both parsing and serialization across all major architectures.</p><p>Automatically updated on every push to <code>main</code> that touches <code>include/</code> or <code>benchmarks/</code>. Runs in parallel on three native GitHub-hosted runners (x86_64 / Apple Silicon / Linux AArch64).</p><table tabindex="0"><thead><tr><th style="text-align:left;">Runner</th><th style="text-align:left;">Architecture</th><th style="text-align:left;">Compiler</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ubuntu-latest</code></td><td style="text-align:left;">x86_64</td><td style="text-align:left;">GCC 13, Release</td></tr><tr><td style="text-align:left;"><code>ubuntu-24.04-arm</code></td><td style="text-align:left;">Linux aarch64</td><td style="text-align:left;">GCC 14, Release</td></tr><tr><td style="text-align:left;"><code>macos-latest</code></td><td style="text-align:left;">Apple Silicon</td><td style="text-align:left;">Apple Clang, Release</td></tr></tbody></table>',4)),i(a),t[1]||(t[1]=e('<hr><h2 id="🔗-language-bindings-performance" tabindex="-1">🔗 Language Bindings Performance <a class="header-anchor" href="#🔗-language-bindings-performance" aria-label="Permalink to &quot;🔗 Language Bindings Performance&quot;">​</a></h2><p><code>qbuem-json</code> provides high-performance bindings for <strong>Python</strong>, <strong>Go</strong>, and <strong>Rust</strong>. The automated benchmark dashboard above includes a dedicated section for these bindings, comparing them against the native JSON libraries in each language.</p><hr><h2 id="🔗-object-mapping-nexus-fusion" tabindex="-1">🔗 Object Mapping (Nexus Fusion) <a class="header-anchor" href="#🔗-object-mapping-nexus-fusion" aria-label="Permalink to &quot;🔗 Object Mapping (Nexus Fusion)&quot;">​</a></h2><p>Unlike DOM-based parsing, <strong>Nexus Fusion</strong> maps JSON directly to C++ structs. These benchmarks measure the latency of full deserialization into complex STL types.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Use the &quot;Dataset&quot; selector above to switch between Standard DOM (twitter.json, etc.) and Object Mapping (Simple Object, Extreme Harsh STL) results.</p></div><hr><h2 id="⚙️-architecture-specific-optimizations" tabindex="-1">⚙️ Architecture-Specific Optimizations <a class="header-anchor" href="#⚙️-architecture-specific-optimizations" aria-label="Permalink to &quot;⚙️ Architecture-Specific Optimizations&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Architecture</th><th style="text-align:left;">Technique</th><th style="text-align:left;">Benefit</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>x86_64</strong></td><td style="text-align:left;">AVX-512 64B/iter Stage 1 scan</td><td style="text-align:left;">Extracts structural tokens in a single pass, ahead of parsing</td></tr><tr><td style="text-align:left;"><strong>x86_64</strong></td><td style="text-align:left;">BMI2 <code>PEXT</code>/<code>PDEP</code></td><td style="text-align:left;">Bit-manipulation for separator extraction without branches</td></tr><tr><td style="text-align:left;"><strong>Apple Silicon</strong></td><td style="text-align:left;">NEON 16B vectorized bitmasks</td><td style="text-align:left;">Branchless character detection tuned for 128-byte M-series cache lines</td></tr><tr><td style="text-align:left;"><strong>All</strong></td><td style="text-align:left;">SWAR (SIMD Within A Register)</td><td style="text-align:left;">8 bytes/cycle string scan using 64-bit GPR — no SIMD required for short strings</td></tr><tr><td style="text-align:left;"><strong>All</strong></td><td style="text-align:left;">KeyLenCache</td><td style="text-align:left;">O(1) key lookup for repeated object schemas (e.g., JSON arrays of same-shape objects)</td></tr><tr><td style="text-align:left;"><strong>All</strong></td><td style="text-align:left;">Schubfach dtoa (R. Giulietti / yyjson port)</td><td style="text-align:left;">Shortest round-trip double→decimal — 2–3× faster than <code>std::to_chars(double)</code>, no trailing zeros</td></tr><tr><td style="text-align:left;"><strong>All</strong></td><td style="text-align:left;">yy-itoa (Y. Yuan / yyjson port)</td><td style="text-align:left;">Integer→decimal via 2-digit table + multiply-shift — zero division instructions</td></tr><tr><td style="text-align:left;"><strong>All</strong></td><td style="text-align:left;">Russ Cox algorithm (parsing only)</td><td style="text-align:left;">Shortest round-trip decimal parsing — no <code>strtod</code>, no bignum fallback</td></tr></tbody></table>',10))])}const b=n(o,[["render",d]]);export{m as __pageData,b as default};
